<template>
  <div class="search">
    <van-row class="topsearchNav">
      <van-col span="2" @click="$router.go(-1)">
        <van-icon class="a-left" name="arrow-left" />
      </van-col>
      <van-col span="19">
         <van-search v-model="value"  placeholder="请输入商品名称" shape="round" />
      </van-col>
      <van-col span="3" class="clearfix">
        <span class="home-t fl" @click="search">确定</span>
      </van-col>
    </van-row>
    <!-- 搜索 -->
      <!-- 如果没有数据，则显示空页面 -->
       <div v-if="this.value== 0" class="empty-box">
      <van-empty description="当前没有搜索的商品哦" />
    </div>
    <div v-else class="page-searching-wrapper">
        <div  class="li-item " v-for="(item,index) in sraechDatas" :key="index" @click="goDetail(item.pid)">
          <div class="img-box ">
            <img
              class="auto-img"
              v-lazy="item.smallImg"
              alt
            />
          </div>
          <div class="r-text">
            <div class="pro-name one-text">{{item.name}}</div>
            <div class="pro-enname one-text">{{item.enname}}</div>
            <div class="pro-price">￥{{item.price}}</div>
          </div>
        </div>
    </div>
  </div>
</template>

<script>
import "../assets/css/search.less";
export default {
  data() {
    return {
     //搜素的商品列表
     sraechDatas:[],
     //默认初始值为空
     value:""
    };
  },
  created(){
      //获取搜索数据
    //   this.getSraechDatas();
  },
  methods:{
      //请求搜索数据商品
    search(){
         //让输入的值赋值给关键字之后，回车产生数据
        let result = this.value;
        this.axios({
            method:'GET',
            url:'/search',
            params:{
                appkey:this.appkey,
                name:result
            }
        }).then(res =>{
            // 
            if(res.data.code == 'Q001'){
                this.sraechDatas = res.data.result;
                // 
            }
        }).catch(err =>{
            
        })
    },
    //点击跳转到详情页
   goDetail(pid){
        this.$router.push({name: 'Detail', query: {pid}});
   }
  }
 
};
</script>

<style lang="scss" scoped>
</style>